mapper.select:
SELECT v.id, v.voucher_no as voucherNo, v.voucher_date as voucherDate, v.attachment_count as attachmentCount, u.real_name as makerName, v.audit_status as auditStatus, CASE v.audit_status WHEN 0 THEN '待审核' WHEN 1 THEN '已审核' WHEN 2 THEN '驳回' END as auditStatusName, v.posting_status as postingStatus, CASE v.posting_status WHEN 0 THEN '未过账' WHEN 1 THEN '已过账' END as postingStatusName, v.total_amount as totalAmount, v.remark, (SELECT COUNT(*) FROM voucher_item WHERE voucher_id = v.id) as itemCount, v.create_time as createTime FROM voucher v LEFT JOIN sys_user u ON v.maker_id = u.id WHERE 1=1
AND v.voucher_no LIKE '%' || #{voucherNo} || '%'
AND v.voucher_date >= #{startDate}
AND v.voucher_date <= #{endDate}
AND v.audit_status = #{auditStatus}
AND v.posting_status = #{postingStatus}
ORDER BY v.voucher_date DESC, v.voucher_no DESC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*) FROM voucher v
WHERE 1=1

    AND v.voucher_no LIKE '%' || #{voucherNo} || '%'


    AND v.voucher_date >= #{startDate}


    AND v.voucher_date <= #{endDate}


    AND v.audit_status = #{auditStatus}


    AND v.posting_status = #{postingStatus}
